#include<bits/stdc++.h>
using namespace std;
struct node
{
    int x,y,id,type,p;
    bool operator<(const node&b)const
    {
        if(y!=b.y)
        {
            return y<b.y;
        }
        return type<b.type;
    }
}a[2500010];
int sum[2000010],ans[500010];
int lowbit(int x)
{
    return x&-x;
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
    }
    return ans;
}
void update(int x,int v)
{
    for(int i=x;i<=2000000;i+=lowbit(i))
    {
        sum[i]+=v;
    }
}
set<int> v;
map<int,int> mp;
int main()
{
    int n,m,k=0;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        a[++k].x=x;
        a[k].y=y;
        a[k].type=0;
        v.insert(x);
    }
    for(int i=1;i<=m;i++)
    {
        int ax,ay,bx,by;
        scanf("%d%d%d%d",&ax,&ay,&bx,&by);
        v.insert(ax-1);
        v.insert(ax);
        v.insert(bx);
        a[++k]=(node){bx,by,i,1,1};
        a[++k]=(node){ax-1,by,i,1,-1};
        a[++k]=(node){bx,ay-1,i,1,-1};
        a[++k]=(node){ax-1,ay-1,i,1,1};
    }
    sort(a+1,a+1+k);
    int cnt=0;
    for(int i:v)
    {
        cnt++;
        mp[i]=cnt;
    }
    for(int i=1;i<=k;i++)
    {
        a[i].x=mp[a[i].x];
    }
    for(int i=1;i<=k;i++)
    {
        // printf("a[%d]=(node){%d,%d,%d,%d,%d}\n",i,a[i].x,a[i].y,a[i].id,a[i].type,a[i].p);
        if(a[i].type==0)
        {
            update(a[i].x,1);
        }
        else
        {
            ans[a[i].id]+=query(a[i].x)*a[i].p;
        }
    }
    for(int i=1;i<=m;i++)
    {
        printf("%d\n",ans[i]);
    }
    return 0;
}
